"use client";

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { FadeIn, SlideUp } from '@/components/animations/MotionUtils';
import { apiClient, ApiError } from '@/lib/apiClient';
import { useAuth } from '@/lib/authContext';

export default function ProfilePage() {
  const router = useRouter();
  const { user: authUser, isLoading: authLoading, updateProfile } = useAuth();

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [mobile, setMobile] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!authLoading && !authUser) router.push('/login');
    if (authUser) {
      setName(authUser.name || '');
      setEmail(authUser.email || '');
      setMobile(authUser.mobile || '');
    }
  }, [authUser, authLoading, router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    setSuccess(false);
    setError('');
    try {
      await updateProfile({ name, email, mobile });
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      if (err instanceof ApiError) setError(err.message.toUpperCase());
      else setError('PROFILE_ARCHIVE_UPDATE_FAILURE');
    } finally {
      setSubmitting(false);
    }
  };

  if (authLoading || !authUser) {
    return (
      <div className="space-y-12">
        <div className="h-4 w-32 bg-white/5 animate-pulse" />
        <div className="h-96 w-full bg-white/5 animate-pulse" />
      </div>
    );
  }

  return (
    <div className="space-y-24 pb-32">
      
      <FadeIn>
        <div className="flex flex-col items-start leading-[0.85]">
          <span className="font-script text-4xl text-[#888888] lowercase mb-8 block">access the</span>
          <h1 className="text-7xl md:text-9xl font-black uppercase tracking-tighter-editorial text-white leading-[0.8]">
             Identity <br /> <span className="text-white/20">Archive</span>
          </h1>
          <p className="text-xl text-[#888888] lowercase mt-12 max-w-xl leading-relaxed">
            authorized personnel identity management and security cipher configuration.
          </p>
        </div>
      </FadeIn>

      <SlideUp delay={0.2} className="max-w-4xl mx-auto">
        <div className="border border-white/5 bg-white/[0.01] p-12 md:p-24 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 select-none pointer-events-none opacity-5 flex flex-col items-end">
             <span className="text-8xl font-black uppercase">{authUser.id.slice(0, 4)}</span>
             <span className="text-2xl font-black uppercase">SECURE_ID</span>
          </div>

          <form onSubmit={handleSubmit} className="space-y-16 relative z-10">
            <div className="flex flex-col group/input">
              <label className="text-[9px] font-bold uppercase tracking-[0.4em] text-white/30 group-focus-within/input:text-white transition-colors mb-4 italic">01. Identity_Name</label>
              <input 
                value={name}
                onChange={(e) => setName(e.target.value)}
                required
                className="bg-transparent border-b border-white/10 py-4 text-white font-black uppercase tracking-tighter focus:outline-none focus:border-white transition-all text-3xl"
              />
            </div>

            <div className="flex flex-col group/input">
              <label className="text-[9px] font-bold uppercase tracking-[0.4em] text-white/30 group-focus-within/input:text-white transition-colors mb-4 italic">02. Electronic_Channel</label>
              <input 
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                readOnly
                className="bg-transparent border-b border-white/5 py-4 text-[#888888] font-black uppercase tracking-tighter focus:outline-none transition-all text-3xl cursor-not-allowed"
              />
              <span className="text-[7px] font-bold text-white/10 uppercase tracking-[0.2em] mt-2">READ_ONLY: PRIMARY_ID_LOCKED</span>
            </div>

            <div className="flex flex-col group/input">
              <label className="text-[9px] font-bold uppercase tracking-[0.4em] text-white/30 group-focus-within/input:text-white transition-colors mb-4 italic">03. Neural_Mobile</label>
              <input 
                type="tel"
                value={mobile}
                onChange={(e) => setMobile(e.target.value)}
                className="bg-transparent border-b border-white/10 py-4 text-white font-black uppercase tracking-tighter focus:outline-none focus:border-white transition-all text-3xl"
              />
            </div>

            <div className="pt-12">
               {error && <p className="mb-8 text-red-500 text-[10px] font-black uppercase tracking-widest text-center">TRANSMISSION_ERROR: {error}</p>}
               {success && <p className="mb-8 text-white text-[10px] font-black uppercase tracking-widest text-center animate-pulse tracking-[0.5em]">IDENTITY_ARCHIVE_SYNCHRONIZED</p>}

               <button 
                 type="submit"
                 disabled={submitting}
                 className="w-full py-10 bg-white text-black font-black uppercase tracking-[0.8em] text-[10px] hover:bg-[#888888] transition-colors"
               >
                 {submitting ? 'SYNCHRONIZING...' : 'LOG CHANGES'}
               </button>
            </div>
          </form>
          
          <div className="absolute bottom-0 left-0 w-full h-px bg-white/5 scale-x-0 group-hover:scale-x-100 transition-transform duration-1000 origin-left" />
        </div>
      </SlideUp>

      <div className="pt-24 text-center">
         <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.6em] block mb-4">CONFIDENTIAL_ARCHIVE_MANAGEMENT_PROTOCOL</span>
         <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.6em]">LAST_SYNCHRONIZATION: {new Date().toLocaleTimeString().toUpperCase()}</span>
      </div>

    </div>
  );
}
